if (typeof p === 'string') {
    const s = p.trim();

    if (s.startsWith('{') || s.startsWith('[')) {
        try {
            msg.payload = JSON.parse(s);
            msg.payloadFormat = 'json';
            return [null, msg];
        } catch (e) {
        }
    }

    const looksLikeCsv =
        (s.includes(';') || s.includes(',')) &&
        s.includes('\n') &&
        !s.startsWith('{') &&
        !s.startsWith('[');

    if (looksLikeCsv) {
        msg.payload = s;
        msg.payloadFormat = 'csv';
        return [msg, null];
    }

    msg.payload = { raw: s };
    msg.payloadFormat = 'raw';
    return [null, msg];
}

if (typeof p === 'object' && p !== null) {
    msg.payload = p;
    msg.payloadFormat = 'object';
    return [null, msg];
}

