const batchSize = 20;
const batchTimeoutMs = 2000;

let batches = flow.get('packet_batches') || {};
let timers = flow.get('packet_batch_timers') || {};

if (!batches[packet]) {
    batches[packet] = [];
}

batches[packet].push(msg.payload);
