const flushPacket = (pkt) => {
    let currentBatches = flow.get('packet_batches') || {};
    let currentTimers = flow.get('packet_batch_timers') || {};

    const arr = currentBatches[pkt] || [];
    if (!arr.length) {
        return null;
    }

    delete currentBatches[pkt];
    flow.set('packet_batches', currentBatches);

    if (currentTimers[pkt]) {
        clearTimeout(currentTimers[pkt]);
        delete currentTimers[pkt];
        flow.set('packet_batch_timers', currentTimers);
    }

    return {
        packet: pkt,
        topic: pkt,
        payload: arr,
        batchSize: arr.length,
        _t_in: msg._t_in
    };
};

if (!timers[packet]) {
