        const out = flushPacket(packet);
        if (out) {
            node.send(out);
        }
    }, batchTimeoutMs);
    flow.set('packet_batch_timers', timers);
}

if (batches[packet].length >= batchSize) {
    return flushPacket(packet);
}

return null;

