function short(v) {
    if (v === null || v === undefined) return "";
    const s = String(v);
    const hash = s.lastIndexOf("#");
    const slash = s.lastIndexOf("/");
    const idx = Math.max(hash, slash);
    return idx >= 0 ? s.substring(idx + 1) : s;
}

const bindings = (((msg.payload || {}).results || {}).bindings) || [];
const columns = msg.meta.columns || [];
const rows = bindings.map(b => {
    const row = {};
    columns.forEach(c => row[c] = short(b[c] && b[c].value));
    return row;
});

let counts = [];
if (msg.meta.countKey) {
    const map = {};
    rows.forEach(r => {
        const key = r[msg.meta.countKey] || "(blank)";
        map[key] = (map[key] || 0) + 1;
    });
    const max = Math.max(1, ...Object.values(map), 1);
    counts = Object.entries(map)
        .sort((a,b) => b[1] - a[1])
        .map(([label, value]) => ({
            label,
            value,
            percent: Math.round((value / max) * 100)
        }));
}

msg.payload = {
    title: msg.meta.title,
    description: msg.meta.description,
    scenario: msg.meta.scenario,
    columns,
    rows,
    counts
};
